from typing import Dict, Any
import json

def audit_session_state(state: Dict[str, Any]) -> Dict[str, list]:
    pii_findings = {'emails': [], 'ssns': [], 'cards': []}
    state_str = json.dumps(state)

    pii_findings['emails'] = re.findall(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', state_str)
    pii_findings['ssns'] = re.findall(r'\b\d{3}-?\d{2}-?\d{4}\b', state_str)
    pii_findings['cards'] = re.findall(r'\b\d{16}\b', state_str)

    return {k: v for k, v in pii_findings.items() if v}

# ADK integration
def before_agent_callback(event):
    if 'session_state' in event:
        findings = audit_session_state(event['session_state'])
        if any(findings.values()):
            print(f'🚨 Session PII: {findings}')
            event['quarantine_state'] = True
    return event

import re
from google.adk import ToolCall

def scan_tool_inputs(tool_call: ToolCall) -> bool:
    params = tool_call.parameters
    param_str = str(params)

    pii_patterns = [
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
        r'\b\d{3}-?\d{2}-?\d{4}\b'
    ]

    for pattern in pii_patterns:
        if re.search(pattern, param_str):
            print(f'🚨 PII in tool {tool_call.name}: {param_str[:50]}...')
            return True
    return False

# ADK callback
def before_agent_callback(event):
    if 'tool_calls' in event:
        for tool_call in event['tool_calls']:
            if scan_tool_inputs(tool_call):
                event['block_tools'] = True
                break
    return event

